const rawOutput = $input.first().json.output;

let aiOutput;

try {
  if (typeof rawOutput === 'object' && rawOutput !== null) {
    aiOutput = rawOutput;
  } else {
    let cleaned = String(rawOutput).trim();

    // Если модель всё же вернула ```json
    cleaned = cleaned
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '');

    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);

    if (!jsonMatch) {
      throw new Error('JSON не найден в ответе');
    }

    aiOutput = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  // При ошибке возвращаем заполненные данные, чтобы не было пустых значений
  return [{
    json: {
      is_arctic: false,
      has_matches: false,
      relevance_score: "0.00", // Форматируем дефолт под DECIMAL(5,2)
      news_data: {
        summary: 'Failed to parse AI response',
      },
      matched_tags: [],
      parse_error: e.message,
      raw_output: typeof rawOutput === 'string' ? rawOutput.slice(0, 1000) : JSON.stringify(rawOutput)
    }
  }];
}

const newsData = aiOutput.news_data || {};
const meta = aiOutput.meta || {};

// Функция для безопасного получения значения с дефолтом
function safeValue(value, defaultValue = '') {
  if (value === null || value === undefined || value === '') {
    return defaultValue;
  }
  return value;
}

// Функция для безопасной даты
function safeDate(value) {
  if (!value || value === '') {
    return new Date().toISOString(); // Текущая дата вместо пустой строки
  }

  // Проверяем, является ли строка валидной датой
  const date = new Date(value);
  if (isNaN(date.getTime())) {
    return new Date().toISOString();
  }

  return date.toISOString();
}

// Функция для валидации и форматирования relevance_score под DECIMAL(5, 2)
function formatRelevanceScore(score) {
  const parsed = parseFloat(score);
  // Если не число или вне диапазона, возвращаем "0.00"
  if (isNaN(parsed) || parsed < 0 || parsed > 100) {
    return "0.00";
  }
  return parsed.toFixed(2); // Возвращает строку вида "57.00"
}

