const newsItems = $('Получаем новости за текущую неделю').all();

// Преобразуем в массив объектов с нужными полями
const newsWithScores = newsItems.map((item, originalIndex) => ({
  id: item.json.id,
  score: parseFloat(item.json.score),
  originalIndex: originalIndex  // сохраняем порядок поступления для tie-breaker
}));

// Сортируем по score (по убыванию) и при одинаковом score - по originalIndex
newsWithScores.sort((a, b) => {
  if (a.score !== b.score) {
    return b.score - a.score;  // больший score выше
  }
  return a.originalIndex - b.originalIndex;  // при равенстве - как пришли
});

// Создаём карту позиций: id новости -> позиция (начиная с 1)
const positionMap = new Map();
newsWithScores.forEach((item, index) => {
  positionMap.set(item.id, index + 1);
});

// Создаём массив связей для каждой новости с добавлением position
const relations = newsItems.map(item => ({
  json: {
    digest_id: digestId,
    news_id: item.json.id,
    score: item.json.score,  // оригинальный score как строка
    position: positionMap.get(item.json.id)  // позиция от 1 до N
  }
}));

return relations;

