// Получаем текущую новость по ссылке на ноду "Для каждой новости3"
const newsItem = $('Для каждой новости').item.json;

// Получаем HTML из новости
let html = newsItem['content:encoded'] || newsItem.content || '';

// Функция для декодирования HTML-сущностей
function decodeHtmlEntities(text) {
  const entities = {
    '&nbsp;': ' ',
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&#x27;': "'",
    '&#x2F;': '/',
    '&#8211;': '–',
    '&#8212;': '—',
    '&#8216;': "'",
    '&#8217;': "'",
    '&#8220;': '"',
    '&#8221;': '"',
    '&#8230;': '...',
    '&mdash;': '—',
    '&ldquo;': '"',
    '&rdquo;': '"',
    '&lsquo;': "'",
    '&rsquo;': "'",
    '&hellip;': '...'
  };

  return text.replace(/&[#\w]+;/g, function(match) {
    return entities[match] || match;
  });
}

// Очищаем HTML более эффективно
let cleanText = html
  // Удаляем скрипты и стили полностью
  .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
  .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '')
  // Удаляем все теги head, meta, link
  .replace(/<head\b[^<]*(?:(?!<\/head>)<[^<]*)*<\/head>/gi, '')
  .replace(/<meta[^>]*>/gi, '')
  .replace(/<link[^>]*>/gi, '')
  // Заменяем блочные теги на переносы строк
  .replace(/<p[^>]*>/gi, '')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<div[^>]*>/gi, '')
  .replace(/<\/div>/gi, '\n')
  .replace(/<h[1-6][^>]*>/gi, '')
  .replace(/<\/h[1-6]>/gi, '\n\n')
  .replace(/<li[^>]*>/gi, '  • ')
  .replace(/<\/li>/gi, '\n')
  .replace(/<ul[^>]*>/gi, '\n')
  .replace(/<\/ul>/gi, '\n')
  .replace(/<ol[^>]*>/gi, '\n')
  .replace(/<\/ol>/gi, '\n')
  .replace(/<tr[^>]*>/gi, '')
  .replace(/<\/tr>/gi, '\n')
  .replace(/<td[^>]*>/gi, '')
  .replace(/<\/td>/gi, ' | ')
  .replace(/<th[^>]*>/gi, '')
  .replace(/<\/th>/gi, ' | ')
  .replace(/<table[^>]*>/gi, '\n')
  .replace(/<\/table>/gi, '\n')
  // Удаляем все остальные HTML теги
  .replace(/<[^>]*>/g, '')
  // Удаляем HTML комментарии
  .replace(/<!--[\s\S]*?-->/g, '')
  // Удаляем CSS и JS блоки (запасной вариант)
  .replace(/{[\s\S]*?}/g, '')
  // Удаляем лишние пробелы в начале строк
  .replace(/^[ \t]+/gm, '')
  // Декодируем HTML сущности
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'")
  .replace(/&#8211;/g, '–')
  .replace(/&#8212;/g, '—')
  .replace(/&#8216;/g, "'")
  .replace(/&#8217;/g, "'")
  .replace(/&#8220;/g, '"')
  .replace(/&#8221;/g, '"')
  .replace(/&#8230;/g, '...')
  .replace(/&mdash;/g, '—')
  .replace(/&ldquo;/g, '"')
  .replace(/&rdquo;/g, '"')
  .replace(/&lsquo;/g, "'")
  .replace(/&rsquo;/g, "'")
  .replace(/&hellip;/g, '...')
  // Удаляем множественные переносы строк
  .replace(/\n\s*\n\s*\n/g, '\n\n')
  .replace(/\n{3,}/g, '\n\n')
  // Удаляем пробелы в конце строк
  .replace(/[ \t]+$/gm, '')
  // Удаляем пустые строки в начале и конце
  .trim();

// Дополнительная очистка от мусорных строк
const lines = cleanText.split('\n');
const filteredLines = lines.filter(line => {
  const trimmedLine = line.trim();
  // Пропускаем пустые строки и строки с мусором
  if (trimmedLine.length === 0) return false;
  if (trimmedLine === '|') return false;
  if (trimmedLine.match(/^[\s|]+$/)) return false;
  if (trimmedLine.length < 2 && trimmedLine !== '•') return false;
  return true;
});

cleanText = filteredLines.join('\n');

// Декодируем оставшиеся HTML сущности (запасной вариант)
cleanText = cleanText.replace(/&#(\d+);/g, function(match, dec) {
  return String.fromCharCode(dec);
});

// Удаляем лишние пробелы между словами
cleanText = cleanText.replace(/\s{2,}/g, ' ');

// Возвращаем только clean_content
return [{
  json: {
    clean_content: cleanText
  }
}];

const items = $input.all();

const validItems = items.filter(item => {
  const data = item.json;

  // Если есть поле error — отбрасываем ЛЮБУЮ ошибку
  if (data.error) {
    console.log(`Отбрасываем ошибку: ${data.error.substring(0, 100)}...`);
    return false;
  }

  // Если нет контента — отбрасываем
  const content = data.content || data['content:encoded'] || data.contentSnippet || '';
  if (!content || content.length < 50) {
    console.log(`Отбрасываем: нет контента или слишком коротко`);
    return false;
  }

  return true;
});

return validItems;

const items = $input.all();
const requests = [];

for (const item of items) {
  const link = item.json.link;

  if (link) {
    requests.push({
      json: {
        url: link,
        // Сохраняем ВСЕ оригинальные RSS-данные
        originalItem: item.json
      }
    });
  }
}

return requests;

const rssItems = $('Отбрасываем ошибки в возврате rss1').all();
const htmlItems = $input.all();
const results = [];
function extractArticleHTML(html) {
  let cleaned = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<aside[\s\S]*?<\/aside>/gi, '')
    .replace(/<form[\s\S]*?<\/form>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<div[^>]*class="[^"]*sharedaddy[^"]*"[\s\S]*?<\/div>\s*<\/div>\s*<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*addtoany[^"]*"[\s\S]*?<\/div>\s*<\/div>/gi, '')
    .replace(/<div[^>]*id="jp-relatedposts"[\s\S]*?<\/div>\s*<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*crp_related[^"]*"[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*id="comments"[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*comment[^"]*"[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*udm-inpage[^"]*"[\s\S]*?<\/div>/gi, '')
    .replace(/<table[\s\S]*?udm-inpage[\s\S]*?<\/table>/gi, '')
    .replace(/<div[^>]*style="clear:both[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*single_postmeta[^"]*"[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*class="[^"]*addtoany_content[^"]*"[\s\S]*?<\/div>\s*<\/div>/gi, '')
    // Исправляем относительные пути изображений
    .replace(/src="(\/sites\/default\/files\/[^"]+)"/g, 'src="https://nsidc.org$1"')
    .replace(/srcset="(\/sites\/default\/files\/[^"]+)"/g, 'srcset="https://nsidc.org$1"');

  const contentPatterns = [
    /<article[\s\S]*?<\/article>/gi,
    /<[^>]*class="[^"]*\b(article|post|content|entry|story|body|text|main)\b[^"]*"[\s\S]*?<\/[^>]+>/gi,
    /<[^>]*id="[^"]*\b(article|post|content|entry|story|body|text|main)\b[^"]*"[\s\S]*?<\/[^>]+>/gi,
    /<main[\s\S]*?<\/main>/gi,
  ];

  let bestBlock = '';

  for (const pattern of contentPatterns) {
    const matches = cleaned.match(pattern);
    if (matches) {
      for (const match of matches) {
        if (match.length > bestBlock.length) {
          bestBlock = match;
        }
      }
    }
  }

  if (bestBlock.length < 200) {
    bestBlock = cleaned;
  }

  return `<div class="extracted-article">${bestBlock}</div>`;
}

for (let i = 0; i < rssItems.length; i++) {
  const rssData = rssItems[i].json;
  const fullHtml = htmlItems[i]?.json?.data || '';

  const articleHtml = extractArticleHTML(fullHtml);

  results.push({
    json: {
      ...rssData,
      'content:encoded': articleHtml,
    }
  });
}

return results;

const items = $input.all();

// Если Directus вернул хотя бы одну запись - дубликат
if (items.length > 0 && items[0].json && items[0].json.id) {
  return [{ json: { is_duplicate: true } }];
}

// Если пусто - новая статья
